INSERT INTO CHAT_REPORT (
	report_id, room_id, reporter_id, report_reason, created_at
) VALUES (
	SEQ_CHAT_REPORT.NEXTVAL, #{room_id}, #{reporter_id}, #{report_reason}, SYSDATE
)

mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rnum, res.* FROM ( SELECT cr.ROOM_ID AS "id", NVL(cr.ROOM_TITLE, fi.TITLE || ' 공식 모임') AS "title", NVL(m.NICKNAME, '공식') AS "hostNickname", cr.ROOM_TYPE AS "roomType", CASE WHEN cr.ROOM_TYPE = 'GROUP' THEN '자유모임' ELSE '축제모임' END AS "category", NVL(cr.ROOM_DESCRIPTION, NVL(fi.OVERVIEW, fi.TITLE || ' 공식 모임방입니다.')) AS "description", (SELECT COUNT(*) FROM CHAT_REPORT WHERE ROOM_ID = cr.ROOM_ID) AS "reports", cr.STATUS AS "status", TO_CHAR(cr.CREATED_AT, 'YYYY.MM.DD') AS "createdAt", (SELECT COUNT(*) FROM CHAT_ROOM_USER WHERE ROOM_ID = cr.ROOM_ID) || '/' || cr.MAX_CAPACITY AS "participants", ( SELECT LISTAGG(REPORT_REASON, ', ') WITHIN GROUP (ORDER BY CREATED_AT DESC) FROM CHAT_REPORT WHERE ROOM_ID = cr.ROOM_ID ) AS "reportReason", ( SELECT MAX(ADMIN_MEMO) FROM MEMBER_REPORT_HISTORY WHERE TARGET_ID = cr.ROOM_ID AND REPORT_TYPE = 'CHAT' ) AS "adminMemo" FROM CHAT_ROOM cr LEFT JOIN MEMBER m ON cr.OWNER_ID = m.MEMBER_ID LEFT JOIN FESTIVAL_INFO fi ON cr.FESTIVAL_ID = fi.CONTENT_ID
cr.ROOM_TYPE IN ('GROUP', 'FESTIVAL')
AND cr.STATUS = #{status}
AND ( cr.ROOM_TITLE LIKE '%' || #{keyword} || '%' OR m.NICKNAME LIKE '%' || #{keyword} || '%' OR TO_CHAR(cr.ROOM_ID) LIKE '%' || #{keyword} || '%' )
AND (SELECT COUNT(*) FROM CHAT_REPORT WHERE ROOM_ID = cr.ROOM_ID) > 0
ORDER BY "reports" DESC, cr.CREATED_AT DESC
ORDER BY cr.CREATED_AT ASC
ORDER BY cr.CREATED_AT DESC
ORDER BY (SELECT COUNT(*) FROM CHAT_ROOM_USER WHERE ROOM_ID = cr.ROOM_ID) DESC, cr.CREATED_AT DESC
) res ) WHERE rnum BETWEEN #{startRow} AND #{endRow}

mapper.update:
UPDATE CHAT_ROOM
SET STATUS = #{status}
WHERE ROOM_ID = #{roomId}

UPDATE MEMBER_REPORT_HISTORY
SET ADMIN_MEMO = #{adminMemo}
WHERE TARGET_ID = #{roomId}
  AND REPORT_TYPE = 'CHAT'

